messageValues.content:
You are an AI crisis detector for a mental health application.
Analyze the user's message. If it contains immediate threat to life, self-harm, or severe abuse, respond with JSON:
{ "crisis_detected": true, "reply": "I want to make sure you are safe. Please consider reaching out to a crisis line immediately." }
Otherwise respond with:
{ "crisis_detected": false }

parameters.jsCode:
const data = $node["Webhook"].json.body;
const persona = data.profile.therapist_persona || "Empathetic Listener";
const theme = data.dynamic_theme || "Unknown";
const memories = (data.memories || []).map(m => `- ${m.type}: ${m.text}`).join('
');
const currentPhase = data.journey_context ? data.journey_context.current_phase : 1;
const pathwayTitle = data.journey_context ? data.journey_context.title : data.pathway;
const messageCount = data.message_count || 1;

// Format up to the last 20 messages for short-term memory context
const transcript = (data.messages || []).slice(-20).map(m => `${m.role === 'user' ? 'Client' : 'Therapist'}: ${m.content}`).join('
');

let pacingInstruction = "";
if (messageCount >= 13 && messageCount < 18) {
  pacingInstruction = `The session is in the Synthesis phase. Begin to transition the conversation toward a closing insight aligned with Phase ${currentPhase}. Help the user identify one small, actionable 'Takeaway Task' based on today's discussion.`;
} else if (messageCount >= 18) {
  pacingInstruction = `The session is nearing its end. Synthesize today's insight, clearly state their specific uniquely tailored 'Takeaway Task' aligned with Phase ${currentPhase}, and gently encourage them to click the 'End Session' button at the bottom of the screen.`;
}

let phaseInstruction = "";
if (currentPhase === 1) phaseInstruction = "Focus purely on somatic grounding, safety, and symptom relief.";
else if (currentPhase === 2) phaseInstruction = "Focus on identifying the environmental or cognitive triggers of their issue.";
else if (currentPhase === 3) phaseInstruction = "Actively challenge the cognitive distortion or behavioral pattern using CBT frameworks.";
else if (currentPhase === 4) phaseInstruction = "Focus on resilience, celebrating wins, and planning for future setbacks.";

const systemPrompt = `You are a mental health coach.
Your persona is: ${persona}
Current clinical theme: ${theme}
The user is currently in Phase ${currentPhase} of the "${pathwayTitle}" therapeutic pathway.
Phase Goal: ${phaseInstruction}

Long-term Client Context (Facts, Triggers, Goals):
${memories}

Recent Session Transcript (Short-term Memory):
${transcript}

INSTRUCTIONS:
Respond empathetically in a single short message. You MUST seamlessly continue the conversation based on the transcript above.

${pacingInstruction}

You also have the ability to inject dynamic tools into the chat. If the user exhibits acute panic or high emotional distress, inject a grounding exercise ('box_breathing' or 'senses_54321'). If they struggle with sleep or physical tension, inject a video ('meditation_sleep' or 'somatic_tension'). If they mention persistent anxiety/worry (GAD-7), stress (PSS-4), or depression (PHQ-9) and you haven't assessed them recently, inject an assessment.

Return ONLY valid JSON in this exact format:
{
  "reply": "<Your empathetic conversational response>",
  "dynamic_content": {
    "type": "video|game|assessment",
    "payload": "<id_of_tool>"
  }
}

(Omit the dynamic_content key entirely if no tool is needed).`;

return [{ json: { systemPrompt } }];

let chatOutput = {};
try {
  chatOutput = JSON.parse($node["Therapist LLM"].json.message.content);
} catch (e) {
  chatOutput = { reply: $node["Therapist LLM"].json.message.content };
}

let merged = {
  reply: chatOutput.reply,
  dynamic_content: chatOutput.dynamic_content,
  guardrail_status: "passed",
  crisis_detected: false
};

// If they went through Discovery node
if ($node["Discovery LLM"]) {
  try {
    const discovery = JSON.parse($node["Discovery LLM"].json.message.content);
    merged.dynamic_theme = discovery.dynamic_theme;
    merged.suggested_pathway = discovery.suggested_pathway;
    merged.pathway_confidence = discovery.pathway_confidence;
  } catch (e) {}
}

return [{ json: merged }];
